const express = require('express');
const cors = require('cors');
const helmet = require('helmet');
const morgan = require('morgan');

// 加载环境变量
require('dotenv').config();

// 导入 SQLite 数据库工具
const sqliteDB = require('./utils/database.sqlite');

// 创建Express应用
const app = express();
const PORT = process.env.PORT || 3000;

// 中间件配置
app.use(helmet());
app.use(cors({
  origin: process.env.CORS_ORIGIN || '*',
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Requested-With', 'X-Trace-Id'],
  credentials: true,
  maxAge: 86400,
}));
app.use(morgan(process.env.NODE_ENV === 'production' ? 'combined' : 'dev'));
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// 路由导入
const authRoutes = require('./routes/auth');
const userRoutes = require('./routes/user');
const orderRoutes = require('./routes/order');
const paymentRoutes = require('./routes/payment');
const rideRoutes = require('./routes/ride');
const shopRoutes = require('./routes/shop');
const mapRoutes = require('./routes/map');

// API路由注册
app.use('/api/v1/auth', authRoutes);
app.use('/api/v1/user', userRoutes);
app.use('/api/v1/order', orderRoutes);
app.use('/api/v1/payment', paymentRoutes);
app.use('/api/v1/ride', rideRoutes);
app.use('/api/v1/shop', shopRoutes);
app.use('/api/v1/map', mapRoutes);

// 健康检查
app.get('/api/v1/health', async (req, res) => {
  const healthcheck = {
    status: 'success',
    data: {
      status: 'healthy',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
      memory: process.memoryUsage(),
      version: process.env.npm_package_version || '1.0.0.0'
    }
  };
  
  try {
    // 检查 SQLite 数据库连接
    const health = await sqliteDB.healthCheck();
    healthcheck.data.database = health.status === 'healthy' ? 'connected' : 'disconnected';
    if (health.status !== 'healthy') {
      healthcheck.data.status = 'degraded';
    }
  } catch (error) {
    healthcheck.data.database = 'disconnected';
    healthcheck.data.status = 'degraded';
  }
  
  res.json(healthcheck);
});

// 404处理
app.use((req, res) => {
  res.status(404).json({
    status: 'error',
    message: '接口不存在'
  });
});

// 错误处理中间件
app.use((err, req, res, next) => {
  console.error('服务器错误:', err);
  res.status(500).json({
    status: 'error',
    message: process.env.NODE_ENV === 'production' 
      ? '服务器内部错误' 
      : err.message || '服务器内部错误'
  });
});

// 启动服务器
(async () => {
  try {
    // 初始化 SQLite 数据库
    await sqliteDB.initDB();
    console.log('SQLite 数据库初始化成功');
  } catch (error) {
    console.warn('SQLite 数据库初始化失败，将在无数据库模式下运行:', error.message);
  }
  
  app.listen(PORT, '0.0.0.0', () => {
    console.log(`🚀 MIXMLAAL API Server running on port ${PORT}`);
    console.log(`📡 API地址: http://localhost:${PORT}/api/v1`);
    console.log(`🗄️  使用 SQLite 数据库（开发环境）`);
  });
})();
